+
+    // -------------------------------------------------------------------------
+    // JSON output tests
+    // -------------------------------------------------------------------------
+
+    #[test]
+    fn stats_rules_json_is_valid() {
+        let env = StatsRulesEnv::new();
+        env.seed_rule_metrics_data();
